import { lazy, Suspense, useEffect, useState } from 'react'
import { getAdditionsForWorld, subscribeEdits } from '../lib/worldEdits'

// Lazy gate around WorldAdditionsImpl — that file imports ~300 prop components
// (~700KB of code). For users with no spawned parts (most first-time visits to
// showcase maps) we never need to load it. Loaded on demand the moment any
// part exists for this world.
const Impl = lazy(() => import('./WorldAdditionsImpl'))

interface Props {
  worldId: string
}

export default function WorldAdditions({ worldId }: Props) {
  const [hasParts, setHasParts] = useState(() => getAdditionsForWorld(worldId).length > 0)

  useEffect(() => {
    return subscribeEdits(() => {
      setHasParts(getAdditionsForWorld(worldId).length > 0)
    })
  }, [worldId])

  if (!hasParts) return null
  return (
    <Suspense fallback={null}>
      <Impl worldId={worldId} />
    </Suspense>
  )
}
