// Sync registry of spawn coords per category. Decoupled from world components
// so GameScene can pick the spawn without importing all 19 heavy world files.
import type { GameMeta } from '../../lib/games'

type Spawn = [number, number, number]

export const SPAWNS: Record<GameMeta['category'], Spawn> = {
  obby:    [0, 3, 2],
  race:    [0, 3, 4],
  tower:   [0, 3, 8],
  garden:  [0, 3, 10],
  pets:    [0, 3, 8],
  town:    [0, 3, 12],
  fashion: [0, 3, 8],
  mystery: [0, 3, -18],
  nights:  [0, 3, 10],
  tycoon:  [0, 3, 12],
  ability: [0, 3, 0],
  petbrain:[0, 3, 6],
  kids:    [0, 1, 8],
  temple:  [0, 3, 55],
  space:   [0, 3, 9],
  cyber:   [0, 3, 7],
  ocean:   [0, 3, 10],
  desert:  [0, 3, 90],
  sandbox: [0, 3, 6],
  rp:      [0, 3, 6],
  sim:     [0, 3, 6],
}

export function getSpawn(cat: GameMeta['category']): Spawn {
  return SPAWNS[cat] ?? [0, 3, 2]
}
