import { Canvas } from '@react-three/fiber'
import { KeyboardControls } from '@react-three/drei'
import { Physics } from '@react-three/rapier'
import { lazy, Suspense } from 'react'
import Player from './Player'
import Sun from './Sun'
import GradientSky from './GradientSky'
import VoxelClouds from './VoxelClouds'
import { getSpawn } from './worlds/worldSpawns'
// World components — lazy-loaded so the Play chunk only pulls in the world the
// user actually visits. Each world is its own chunk; loaded on demand via Suspense.
const ObbyWorld           = lazy(() => import('./worlds/ObbyWorld'))
const RaceWorld           = lazy(() => import('./worlds/RaceWorld'))
const SandboxWorld        = lazy(() => import('./worlds/SandboxWorld'))
const TowerWorld          = lazy(() => import('./worlds/TowerWorld'))
const GardenWorld         = lazy(() => import('./worlds/GardenWorld'))
const PetSimWorld         = lazy(() => import('./worlds/PetSimWorld'))
const BotTownWorld        = lazy(() => import('./worlds/BotTownWorld'))
const FashionWorld        = lazy(() => import('./worlds/FashionWorld'))
const MysteryWorld        = lazy(() => import('./worlds/MysteryWorld'))
const NightsWorld         = lazy(() => import('./worlds/NightsWorld'))
const TycoonWorld         = lazy(() => import('./worlds/TycoonWorld'))
const AbilityBuilderWorld = lazy(() => import('./worlds/AbilityBuilderWorld'))
const PetBrainWorld       = lazy(() => import('./worlds/PetBrainWorld'))
const TempleWorld         = lazy(() => import('./worlds/TempleWorld'))
const SpaceStationWorld   = lazy(() => import('./worlds/SpaceStationWorld'))
const CyberCityWorld      = lazy(() => import('./worlds/CyberCityWorld'))
const OceanWorld          = lazy(() => import('./worlds/OceanWorld'))
const DesertWorld         = lazy(() => import('./worlds/DesertWorld'))
const KidsWorld           = lazy(() => import('./worlds/KidsWorld'))
import CameraController from './CameraController'
import AdaptiveDPR from './AdaptiveDPR'
import Scriptable from './Scriptable'
import UniversalClickCatcher from './UniversalClickCatcher'
import FocusedObjectIndicator from './FocusedObjectIndicator'
import WorldAdditions from './WorldAdditions'
import WorldOverridesApplier from './WorldOverridesApplier'
import ToonOverride from './ToonOverride'
import GroundOverride from './GroundOverride'
import PostFX from './PostFX'
import AmbientDust from './AmbientDust'
import ScriptGhosts from './ScriptGhosts'
import { getWorldTargets } from './worlds/scriptableTargets'
import type { GameMeta } from '../lib/games'
import type { Avatar } from '../lib/avatars'
import { getPhysicsTimestep, getShadowMapSize, canShadows } from '../lib/deviceTier'
import type { ComponentType } from 'react'

const SHADOW_MAP_SIZE = getShadowMapSize()
const PHYSICS_TIMESTEP = getPhysicsTimestep()
const SHADOWS_ON = canShadows()

const KEYS = [
  { name: 'forward', keys: ['KeyW', 'ArrowUp'] },
  { name: 'back', keys: ['KeyS', 'ArrowDown'] },
  { name: 'left', keys: ['KeyA', 'ArrowLeft'] },
  { name: 'right', keys: ['KeyD', 'ArrowRight'] },
  { name: 'jump', keys: ['Space'] },
  { name: 'sprint', keys: ['ShiftLeft', 'ShiftRight'] },
]

interface Props {
  game: GameMeta
  avatar: Avatar
}

// Позиция солнца: высоко-слева-сбоку — даёт драматичные тени, но не выгорает.
const SUN_POS: [number, number, number] = [50, 45, 20]
// Контровая подсветка с противоположной стороны — тень не чернеет.
const FILL_LIGHT_POS: [number, number, number] = [-30, 20, -20]

export default function GameScene({ game, avatar }: Props) {
  const W = pickWorld(game.category)
  const spawn = getSpawn(game.category)
  const scriptTargets = getWorldTargets(game.id, game.category)
  return (
    <KeyboardControls map={KEYS}>
      <Canvas
        shadows={SHADOWS_ON}
        camera={{ position: [spawn[0], spawn[1] + 4, spawn[2] + 8], fov: 60, near: 0.1, far: 200 }}
        gl={{ antialias: false, powerPreference: 'high-performance' }}
        dpr={[0.75, 1.25]}
        onContextMenu={(e) => e.preventDefault()}
      >
        {/* Градиентное голубое небо через shader — всегда голубое */}
        <GradientSky top="#3d88ff" bottom="#b8e1ff" />
        {/* Pixel-voxel облака, медленно плывут */}
        <VoxelClouds />
        {/* Видимое солнце */}
        <Sun position={SUN_POS} />
        {/* Мягкий туман только в самой дали, не глушит небо */}
        <fog attach="fog" args={['#b8e1ff', 80, 190]} />

        {/* Освещение: тёплое солнце + голубая заливка тени + сильный ambient.
            Избегаем "чёрного силуэта" персонажа когда он стоит между камерой и солнцем. */}
        <ambientLight intensity={0.75} />
        <hemisphereLight args={['#bfe4ff', '#5bc87d', 0.55]} />
        <directionalLight
          position={SUN_POS}
          intensity={1.3}
          color="#fff3d8"
          castShadow={SHADOWS_ON}
          shadow-mapSize-width={SHADOW_MAP_SIZE}
          shadow-mapSize-height={SHADOW_MAP_SIZE}
          shadow-camera-near={0.5}
          shadow-camera-far={100}
          shadow-camera-left={-35}
          shadow-camera-right={35}
          shadow-camera-top={35}
          shadow-camera-bottom={-35}
          shadow-bias={-0.00005}
          shadow-normalBias={0.03}
        />
        {/* Контровая подсветка с противоположной стороны — тень не чернеет */}
        <directionalLight position={FILL_LIGHT_POS} intensity={0.45} color="#b0d8ff" />
        {/* Subtle top-down rim for character readability */}
        <directionalLight position={[0, 30, -40]} intensity={0.25} color="#e8f4ff" />

        <Physics gravity={[0, -25, 0]} timeStep={PHYSICS_TIMESTEP}>
          <UniversalClickCatcher worldId={game.id}>
            <Suspense fallback={null}>
              <W />
            </Suspense>
            <WorldAdditions worldId={game.id} />
            {scriptTargets.map((t) => (
              <Scriptable
                key={t.id}
                worldId={game.id}
                objectId={t.id}
                pos={t.pos}
                label={t.label}
                radius={t.radius ?? 1.2}
              />
            ))}
            {/* Невидимые Scriptable для universal-click скриптов (at_*) */}
            <ScriptGhosts
              worldId={game.id}
              knownIds={new Set(scriptTargets.map((t) => t.id))}
            />
          </UniversalClickCatcher>
          <Player avatar={avatar} startPos={spawn} />
        </Physics>
        {/* Applier живёт ВНЕ Physics — ему нужен доступ к scene через useThree */}
        <WorldOverridesApplier worldId={game.id} />
        {/* Cel / toon shading — заменяет MeshStandardMaterial на MeshToonMaterial */}
        <ToonOverride />
        {/* Procedural noise-variation shader for large ground planes */}
        <GroundOverride />
        <PostFX />
        <AmbientDust />
        <CameraController />
        <FocusedObjectIndicator />
        <AdaptiveDPR />
      </Canvas>
    </KeyboardControls>
  )
}

function pickWorld(cat: GameMeta['category']): ComponentType {
  switch (cat) {
    case 'race':    return RaceWorld
    case 'tower':   return TowerWorld
    case 'garden':  return GardenWorld
    case 'pets':    return PetSimWorld
    case 'town':    return BotTownWorld
    case 'fashion': return FashionWorld
    case 'mystery': return MysteryWorld
    case 'nights':  return NightsWorld
    case 'tycoon':  return TycoonWorld
    case 'ability': return AbilityBuilderWorld
    case 'petbrain': return PetBrainWorld
    case 'kids':    return KidsWorld
    case 'sandbox':
    case 'rp':
    case 'sim':     return SandboxWorld
    case 'temple':  return TempleWorld
    case 'space':   return SpaceStationWorld
    case 'cyber':   return CyberCityWorld
    case 'ocean':   return OceanWorld
    case 'desert':  return DesertWorld
    case 'obby':
    default:        return ObbyWorld
  }
}
